function solve(words: string[]): number[] {
    const n = words.length;
    if (n === 1) {
        return [0];
    }

    function getCommonPrefixLength(a: string, b: string): number {
        let len = 0;
        while (len < a.length && len < b.length && a.charAt(len) === b.charAt(len)) {
            len++;
        }
        return len;
    }

    const max_prefix: number[] = [];
    for (let j = 0; j < n - 1; j++) {
        max_prefix.push(getCommonPrefixLength(words[j], words[j + 1]));
    }

    const prefix_max: number[] = new Array(n - 1);
    prefix_max[0] = max_prefix[0];
    for (let i = 1; i < n - 1; i++) {
        prefix_max[i] = Math.max(prefix_max[i - 1], max_prefix[i]);
    }

    const suffix_max: number[] = new Array(n - 1);
    suffix_max[n - 2] = max_prefix[n - 2];
    for (let i = n - 3; i >= 0; i--) {
        suffix_max[i] = Math.max(max_prefix[i], suffix_max[i + 1]);
    }

    const answer: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        let left_max = 0;
        if (i > 0) {
            if (i - 2 >= 0) {
                left_max = prefix_max[i - 2];
            }
        }

        let right_max = 0;
        if (i < n - 1) {
            if (i + 1 <= n - 2) {
                right_max = suffix_max[i + 1];
            }
        }

        let cross = 0;
        if (i > 0 && i < n - 1) {
            cross = getCommonPrefixLength(words[i - 1], words[i + 1]);
        }

        answer[i] = Math.max(left_max, right_max, cross);
    }

    return answer;
}

